        _mockHttp.Setup(h => h.GetAsync(
            It.Is<string>(u => u.Contains("_page=1")),
            It.IsAny<CancellationToken>()))
            .ReturnsAsync(TwoPostsJson);

        _mockHttp.Setup(h => h.GetAsync(
