     1→// TDD GREEN: CacheService created to make CacheServiceTests pass.
     2→//
     3→// Design decisions:
     4→// - Depends on IFileSystem so tests never touch real disk.
     5→// - Keys are hashed (MD5) to produce safe, collision-resistant filenames.
     6→// - Serializes/deserializes with System.Text.Json using camelCase policy,
     7→//   matching the shape returned by JSONPlaceholder.
     8→
     9→using System.Security.Cryptography;
    10→using System.Text;
    11→using System.Text.Json;
    12→
    13→namespace RestApiClient;
    14→
    15→/// <summary>
    16→/// Caches arbitrary objects as JSON files in a local directory.
    17→/// All file I/O is delegated to <see cref="IFileSystem"/> for testability.
    18→/// </summary>
    19→public class CacheService
    20→{
    21→    private readonly IFileSystem _fs;
    22→    private readonly string _cacheDir;
    23→
    24→    private static readonly JsonSerializerOptions JsonOpts = new()
    25→    {
    26→        PropertyNamingPolicy        = JsonNamingPolicy.CamelCase,
    27→        PropertyNameCaseInsensitive = true,
    28→    };
    29→
    30→    public CacheService(IFileSystem fileSystem, string cacheDirectory)
    31→    {
    32→        _fs       = fileSystem;
    33→        _cacheDir = cacheDirectory;
    34→    }
    35→
    36→    /// <summary>
    37→    /// Returns the cached value for <paramref name="key"/>, or
    38→    /// <c>null</c> if it has not been cached yet (cache miss).
    39→    /// </summary>
    40→    public async Task<T?> GetAsync<T>(string key) where T : class
    41→    {
    42→        var path = CachePath(key);
    43→        if (!_fs.FileExists(path)) return null;
    44→
    45→        var json = await _fs.ReadAllTextAsync(path);
    46→        return JsonSerializer.Deserialize<T>(json, JsonOpts);
    47→    }
    48→
    49→    /// <summary>Serializes <paramref name="value"/> and writes it to cache.</summary>
    50→    public async Task SetAsync<T>(string key, T value) where T : class
    51→    {
    52→        // Ensure cache directory exists before first write
    53→        _fs.EnsureDirectoryExists(_cacheDir);
    54→
    55→        var path = GetCachePath(key);
    56→        var json = JsonSerializer.Serialize(value, JsonOpts);
    57→        await _fs.WriteAllTextAsync(path, json);
    58→    }
    59→
    60→    /// <summary>Returns <c>true</c> if a cache entry exists for <paramref name="key"/>.</summary>
    61→    public bool Exists(string key) => _fs.FileExists(CachePath(key));
    62→
    63→    // -------------------------------------------------------------------------
    64→    // Helpers
    65→    // -------------------------------------------------------------------------
    66→
    67→    /// <summary>
    68→    /// Converts a logical cache key into a filesystem path.
    69→    /// MD5 is used purely for name-safety — not for security.
    70→    /// </summary>
    71→    private string GetCachePath(string key) => CachePath(key);
    72→
    73→    private string CachePath(string key)
    74→    {
    75→        using var md5  = MD5.Create();
    76→        var hashBytes  = md5.ComputeHash(Encoding.UTF8.GetBytes(key));
    77→        var hash       = Convert.ToHexString(hashBytes);
    78→        return Path.Combine(_cacheDir, $"{hash}.json");
    79→    }
    80→}
