     1→// TDD GREEN: RetryPolicy created to make RetryPolicyTests pass.
     2→//
     3→// Design decisions:
     4→// - The sleep function is injected via constructor so tests can pass a no-op
     5→//   and never actually wait, while production uses Task.Delay.
     6→// - Exponential delay formula: baseDelayMs × 2^attempt  (attempt starts at 0)
     7→//   e.g. base=1000ms → 1000ms, 2000ms, 4000ms for 3 retries.
     8→// - OperationCanceledException is re-thrown immediately without retry, so
     9→//   callers can cancel a long-running fetch cleanly.
    10→// - After maxRetries+1 total attempts the exception is wrapped in
    11→//   RetryExhaustedException to give callers a clear signal.
    12→
    13→namespace RestApiClient;
    14→
    15→/// <summary>
    16→/// Executes an async operation with exponential-backoff retry on failure.
    17→/// </summary>
    18→public class RetryPolicy
    19→{
    20→    private readonly int _maxRetries;
    21→    private readonly int _baseDelayMs;
    22→    private readonly Func<TimeSpan, CancellationToken, Task> _sleep;
    23→
    24→    /// <summary>
    25→    /// Production constructor — uses <see cref="Task.Delay(TimeSpan,CancellationToken)"/>
    26→    /// for real backoff.
    27→    /// </summary>
    28→    public RetryPolicy(int maxRetries = 3, int baseDelayMs = 1000)
    29→        : this(maxRetries, baseDelayMs, Task.Delay) { }
    30→
    31→    /// <summary>
    32→    /// Testable constructor — inject a custom sleep function (e.g. no-op)
    33→    /// to avoid real delays in unit tests.
    34→    /// </summary>
    35→    public RetryPolicy(
    36→        int maxRetries,
    37→        int baseDelayMs,
    38→        Func<TimeSpan, CancellationToken, Task> sleep)
    39→    {
    40→        _maxRetries  = maxRetries;
    41→        _baseDelayMs = baseDelayMs;
    42→        _sleep       = sleep;
    43→    }
    44→
    45→    /// <summary>
    46→    /// Executes <paramref name="operation"/> and retries on failure with
    47→    /// exponential backoff up to <c>maxRetries</c> times.
    48→    /// </summary>
    49→    /// <exception cref="RetryExhaustedException">
    50→    /// Thrown when all attempts have failed; wraps the last exception.
    51→    /// </exception>
    52→    public async Task<T> ExecuteAsync<T>(
    53→        Func<Task<T>> operation,
    54→        CancellationToken ct = default)
    55→    {
    56→        Exception? lastEx = null;
    57→
    58→        for (var attempt = 0; attempt <= _maxRetries; attempt++)
    59→        {
    60→            try
    61→            {
    62→                return await operation();
    63→            }
    64→            catch (OperationCanceledException)
    65→            {
    66→                // Never retry cancellations — propagate immediately
    67→                throw;
    68→            }
    69→            catch (Exception ex)
    70→            {
    71→                lastEx = ex;
    72→
    73→                if (attempt < _maxRetries)
    74→                {
    75→                    // Exponential backoff: base × 2^attempt
    76→                    var delay = TimeSpan.FromMilliseconds(
