        Func<TimeSpan, CancellationToken, Task> captureSleep = (d, _) =>
        {
            delays.Add(d);
            return Task.CompletedTask;
        };

        var policy = new RetryPolicy(maxRetries: 3, baseDelayMs: 1000, sleep: captureSleep);

